UPDATE XBOLTADM.TB_ITEM 
SET 
	Deleted = '1'
WHERE
	ToItemID = #{ToItemID} AND FromItemID = #{FromItemID}
	or	
	ToItemID = #{FromItemID} AND FromItemID = #{ToItemID}
	or
	ItemID = #{ToItemID}

