DELETE XBOLTADM.TB_ITEM_ATTR 
WHERE
	ItemID = 
	(	
		SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE
		ToItemID = #{ToItemID} AND FromItemID = #{FromItemID}
		or	
		ToItemID = #{FromItemID} AND FromItemID = #{ToItemID}
	)

DELETE XBOLTADM.TB_ITEM 
WHERE
	ToItemID = #{ToItemID} AND FromItemID = #{FromItemID}
	or	
	ToItemID = #{FromItemID} AND FromItemID = #{ToItemID}

mapper.update:
UPDATE XBOLTADM.TB_ITEM 
SET 
	LastUser = #{LastUser}
	, LastUpdated = getdate()
	
		, ClassCode = #{ClassCode}
	
	
		, Identifier = #{Identifier}
	
	
		, Status = #{Status}
	
	
		, RefItemID = #{RefItemID}
		, RefItemID = null
	
	
		, Deleted = #{deleted}
	
WHERE
	ItemID = #{ItemID}

UPDATE 
	XBOLTADM.TB_ITEM_ATTR
SET
	PlainText = #{PlainText},
	LastUpdated = GetDate()
	
		,LovCode = #{LovCode}
	
	
		, ItemTypeCode = #{ItemTypeCode}
		, ItemTypeCode =  (Select ItemTypeCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})
	
	
		, ClasseCode = #{ClasseCode}
		 , ClassCode = (Select ClassCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})
			
WHERE
	ItemID = #{ItemID}
	AND AttrTypeCode = #{AttrTypeCode}
	AND LanguageID = #{languageID}

 		UPDATE 	XBOLTADM.TB_CHANGE_SET 		
 		SET
			    AuthorID = #{AuthorID}
			    ,AuthorTeamID = #{AuthorTeamID}
				
					,Status = #{Status}
				
			    ,AuthorName = #{AuthorName}		
				,ChangeType = #{ChangeType}
				,Description = #{Description}
		WHERE
				ChangeSetID = #{ChangeSetID}

UPDATE 	XBOLTADM.TB_ITEM 		
SET
	FromItemID = #{setFromItemID}
WHERE
	ToItemID = #{ToItemID} AND FromItemID = #{FromItemID}

mapper.insert:
INSERT INTO XBOLTADM.TB_ITEM
	(
		  Version  
		, CreationTime
		, Creator
		, LastUpdated
		, LastUser
		, CategoryCode
		, ClassCode
		, CompanyID
		, ItemID
		, ItemTypeCode
		, ToItemID
		, FromItemID
		, Identifier
		, OwnerTeamId
		, Deleted				
		, AuthorID
		, Status
		, RefItemID
		, ProjectID
		, CurChangeSet
		, ParentID
	) VALUES (
	  	  #{Version}
		, getdate()
		, #{Creator}
		, getdate()
		, #{Creator}
		, #{CategoryCode}
		, #{ClassCode}
		
			, #{CompanyID}
			, (Select CompanyID FROM XBOLTADM.TB_TEAM WHERE TeamID = #{OwnerTeamId})
		
		, #{ItemID}
		, #{ItemTypeCode}
		, #{ToItemID}
		, #{FromItemID}
		, #{Identifier}
		, #{OwnerTeamId}
		, #{Deleted}				
		, #{AuthorID}
		, #{Status}
		, #{RefItemID}
		, #{ProjectID}
		, #{CurChangeSet}
		, #{ParentID}		
	)

		INSERT INTO XBOLTADM.TB_ITEM
			(
				  Version  
				, CreationTime
				, Creator
				, LastUpdated
				, LastUser
				, CategoryCode
				, ClassCode
				, CompanyID
				, ItemID
				, ItemTypeCode
				, ToItemID
				, FromItemID
				, Identifier
				, OwnerTeamId
				, Deleted				
				, AuthorID
			) VALUES (
			  	  #{Version}
				, getdate()
				, #{Creator}
				, getdate()
				, #{Creator}
				, #{CategoryCode}
				, (Select ClassCode From XBOLTADM.TB_ITEM WHERE ItemID = #{FromItemID})
				, #{CompanyID}
				, #{ItemID}

				, #{ItemTypeCode}
				, #{ToItemID}
				, #{FromItemID}
				, #{Identifier}
				, #{OwnerTeamId}
				, #{Deleted}
				
				, #{AuthorID}
			)

INSERT INTO
	XBOLTADM.TB_ITEM_ATTR
	(
		PlainText
		,LanguageID
		,ItemID
		,AttrTypeCode
		,LovCode
		,ItemTypeCode
		,ClassCode
		,LastUpdated
	)
VALUES
	(
	#{PlainText}
	, #{languageID}
	, #{ItemID}
	, #{AttrTypeCode}
	, #{LovCode}	
	, #{ItemTypeCode}
	, (Select ClassCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})
	, GETDATE()
	)

INSERT INTO XBOLTADM.TB_ITEM_ATTR
	(
		  PlainText
		, LanguageID
		, ItemID
		, AttrTypeCode
		, LovCode
		, ItemTypeCode
		, ClassCode
		, LastUpdated
	) VALUES (
	  	  #{PlainText}
		, #{languageID}
		, #{ItemID}
		, #{AttrTypeCode}
		, #{LovCode}
		, (Select ItemTypeCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})
		, (Select ClassCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})
		, GETDATE()
	)

mapper.select:
SELECT ItemTypeCode
FROM XBOLTADM.TB_ITEM
WHERE ItemID = #{s_itemID}

SELECT ClassCode
FROM XBOLTADM.TB_ITEM
WHERE ItemID = #{s_itemID}

SELECT Distinct Top 1 DefDimValueID
FROM XBOLTADM.TB_ARC_FILTER_DIM
WHERE ArcCode = #{option}

SELECT 
	TM.MemberID, TM.Name, TM.LoginID, TM.Email, ISNULL(TTC.Name, '') as CompanyID, TTT.Name AS TeamID
	, TM.Authority, TM.RetireDate  AS RetireDate
FROM 
	XBOLTADM.TB_MEMBER TM
	Left Outer Join XBOLTADM.TB_TEAM_TXT TTC on TM.CompanyID = TTC.TeamID AND TTC.LanguageID = #{languageID}
	Left Outer Join XBOLTADM.TB_TEAM_TXT TTT on TM.TeamID = TTT.TeamID AND TTT.LanguageID = #{languageID}
WHERE
	TM.TeamID = #{TeamID}
	
		AND TM.Name Like '%'+#{Name}+'%'

SELECT 
	Distinct ItemTypeCode 
FROM 
	XBOLTADM.TB_ITEM_TYPE
WHERE 
	ToItemTypeCode = (
		Select ItemTypeCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ToItemID}
		)
	AND FromItemTypeCode = (
		Select ItemTypeCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{FromItemID}
		)
	AND Category IN ('CN', 'CN1' , 'ST2')

Select TI.ItemID, TI.Identifier, TIA.PlainText AS ItemName From XBOLTADM.TB_ITEM TI Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Where 1=1
And TI.RefItemID = #{refItemID}
And TI.ItemID = (Select RefItemID From XBOLTADM.TB_Item Where ItemID = #{mstItemID} And RefItemID != #{mstItemID})

SELECT distinct TATA.SortNum ,TATA.AttrTypeCode AS AttrTypeCode , ISNULL(TD.Name, '') AS Name , CASE TAT.DataType WHEN 'LOV' THEN TATL.Value WHEN 'MLOV' THEN '' ELSE ISNULL(TIA.PlainText, '') END PlainText , CASE TAT.DataType WHEN 'MLOV' Then '' ELSE ISNULL(TIA.LovCode, '') END AS LovCode , ISNULL(TATL.AttrTypeCode, '') AS BaseLovCode , TAT.DataType , TAT.IsComLang , TAT.HTML , ISNULL(TATA.Mandatory, '') AS Mandatory , ISNULL(TAT.Editable, '') AS Editable , TATA.Link , TM.URL , ISNULL(TATA.AreaHeight, '20') AS AreaHeight FROM XBOLTADM.TB_ATTR_TYPE_ALLOCATION TATA Left Outer Join XBOLTADM.TB_ITEM_ATTR_REV TIA ON TATA.AttrTypeCode = TIA.AttrTypeCode AND TIA.ItemID = #{s_itemID} And TIA.ChangeSetID = #{changeSetID}
AND TIA.LanguageID = #{languageID} AND TIA.LanguageID = #{defaultLang}
Left Outer Join XBOLTADM.TB_DICTIONARY TD on TATA.AttrTypeCode = TD.TypeCode
AND TD.LanguageID = #{loginLangType} AND TD.LanguageID = #{languageID}
Left Outer join XBOLTADM.TB_ATTR_TYPE_LOV TATL on TATA.AttrTypeCode = TATL.AttrTypeCode AND TIA.LovCode = TATL.LovCode AND TATL.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT on TATA.AttrTypeCode = TAT.AttrTypeCode Left Outer Join XBOLTADM.TB_MENU TM ON TATA.Link = TM.MenuID WHERE TATA.ItemClassCode = (SELECT ClassCode From XBOLTADM.TB_ITEM WHERE ItemID = #{s_itemID}) AND TATA.Invisible = 0
AND TAT.AttrTypeCode = #{AttrTypeCode}
AND TAT.AttrTypeCode IN ${AttrTypeCodes}
AND TAT.IsComLang = 1 AND TAT.DataType != 'LOV'
AND TAT.Editable = #{Editable}
ORDER BY TATA.SortNum ASC

Select  Top 1 ModelID From XBOLTADM.TB_MODEL 
Where ChangeSetID = #{changeSetID} 
And ItemID = #{itemID}

Select MemberID From XBOLTADM.TB_MY_ITEM 
Where ItemID = #{itemID}
	
	And AccessRight = 'U'
	
	
	And MemberID = #{userID}

Select T.MemberID, T.Name , T.Photo From ( Select TI.AuthorID As MemberID, TM.Name AS Name, 0 AS Num, Case When ISNULL(TM.Photo,'blank_photo.png') = 'blank_photo.png' Then #{blankPhotoUrlPath} Else CAST(#{photoUrlPath} AS varchar(100)) + ISNULL(TM.Photo,'blank_photo.png') END AS Photo
From XBOLTADM.TB_ITEM TI Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TI.AuthorID Where TI.ItemID = #{itemID}
UNION
Select TMI.MemberID As MemberID, TM.Name AS Name, 1 AS Num, Case When ISNULL(TM.Photo,'blank_photo.png') = 'blank_photo.png' Then #{blankPhotoUrlPath} Else CAST(#{photoUrlPath} AS varchar(50)) + ISNULL(TM.Photo,'blank_photo.png') END AS Photo
From XBOLTADM.TB_MY_ITEM TMI Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TMI.MemberID
Where TMI.ItemID = #{itemID} And AccessRight = 'U' And TMI.MemberID Not In (Select AuthorID from XBOLTADM.TB_ITEM where ItemID = #{itemID})
And TMI.AssignmentType = #{assignmentType}
) T Order By Num

Select MemberID From XBOLTADM.TB_MY_ITEM
Where ItemID = #{ItemID}
And AccessRight = 'U'

Select Identifier From XBOLTADM.TB_ITEM
Where ItemID IN(
				Select ToItemID
				From XBOLTADM.TB_ITEM		
				Where FromItemID = #{itemID}
				)

mapper.update:
UPDATE 
	XBOLTADM.TB_ITEM_OCC_ATTR
SET
	PlainText = #{PlainText}
WHERE
	ItemOccID = #{ItemOccID}
	and AttrTypeCode = #{AttrTypeCode}

UPDATE
	XBOLTADM.TB_ITEM
SET
	OwnerTeamID = #{s_itemID}
WHERE
	ItemID = #{ItemID}

UPDATE XBOLTADM.TB_ITEM SET AuthorID = #{s_itemID} , OwnerTeamID = (SELECT TeamID FROM XBOLTADM.TB_MEMBER WHERE MemberID = #{s_itemID}) WHERE ItemID = #{ItemID} or ItemID in (
SELECT ToItemID FROM XBOLTADM.TB_ITEM ITM WHERE ITM.FromItemID = #{ItemID} /*arg 0: 선택한 Item*/ AND ITM.CategoryCode = 'ST1' AND ITM.Deleted != '1'
)

mapper.select:
	SELECT TI.ItemID, ISNULL(TIS.SCOUNT, 0) AS SCOUNT, TIA.PlainText as ItemName, TD.Name as ClassName, ISNULL(TT.Name, '') as TeamName, TOT.Name as OwnerTeamName
		,TM.Name, Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated, TI.Version, TI.Identifier, TIF.PlainText as ProcessInfo
	FROM
		XBOLTADM.TB_ITEM TI
		Left outer join (
			SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT 
			FROM XBOLTADM.TB_ITEM 
			WHERE Deleted != '1'
			GROUP BY FromItemID 
			) TIS on TIS.FromItemID = TI.ItemID
		Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID
		Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_ITEM_ATTR TIF on TI.ItemID = TIF.ItemID AND TIF.AttrTypeCode = 'AT00003' AND TIF.LanguageID = #{languageID}
	WHERE TI.ItemID in (
		Select ToItemID FROM XBOLTADM.TB_ITEM
		Where FromItemID =  #{s_itemID}
			AND CategoryCode in ( 'ST1' , 'ST2')
	 )
		
		AND TIA.PlainText Like '%'+#{searchName}+'%'
		
		
		AND TI.Identifier Like '%'+#{searchID}+'%'
			
	AND Deleted != '1'	 

	 	
	order by
		TI.ClassCode ASC, TIA.PlainText ASC

 SELECT 
 		TI.ItemID, TIF.ItemTypeCode, TIF.ItemID, TIF.CategoryCode, ISNULL(TIS.SCOUNT, 0) AS SCOUNT
 		, TIFA.PlainText as ParentName, TIA.PlainText as ItemName, TD.Name as ClassName, ISNULL(TT.Name, '') as TeamName, TOT.Name as OwnerTeamName
		,TM.Name, Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated, TI.Version, TI.Identifier, TIFA2.PlainText as ProcessInfo
		, XBOLTADM.fn_GetMyAbsPathForList(TI.ItemID, #{languageID}) AS getPath
	FROM
		XBOLTADM.TB_ITEM TI
		Left outer join (
			SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT 
			FROM XBOLTADM.TB_ITEM 
			WHERE Deleted != '1'
			GROUP BY FromItemID 
			) TIS on TIS.FromItemID = TI.ItemID
		Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID AND TIF.CategoryCode = 'ST1'
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIFA on TIF.FromItemID = TIFA.ItemID AND TIFA.AttrTypeCode = 'AT00001' AND TIFA.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID
		Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_ITEM_ATTR TIFA2 on TI.ItemID = TIFA2.ItemID AND TIFA2.AttrTypeCode = 'AT00003' AND TIFA2.LanguageID =  #{languageID}
		
		Left outer join XBOLTADM.TB_ITEM TI2 on TI2.FromItemID = TI.ItemID AND TI2.ToItemID = #{elmItemID} AND TI2.CategoryCode = 'CN' and TI2.Deleted != '1'
		
	WHERE TI.ItemID in (
		Select Distinct TI.ItemID
		From XBOLTADM.TB_ITEM TI
		WHERE 
			TI.ItemID in (
				Select FromItemID
				From XBOLTADM.TB_ITEM
				WHERE ToItemID =  #{s_itemID}
					AND CategoryCode = 'CN'
					AND Deleted != '1'
			)
			
			OR
			TI.ItemID in (
				Select ToItemID
				From XBOLTADM.TB_ITEM 
				WHERE FromItemID =  #{s_itemID}
					AND CategoryCode = 'CN'
					AND Deleted != '1'
			)
			
	 )
		
		AND TI.ClassCode = #{mainClassCode}
		
		
		AND TI.CompanyID = #{mainCompanyCode}
		
		AND TI.CategoryCode != 'TOJ' 		
		
			AND TIF.ItemTypeCode = #{cxnTypeCode}
		
		
		AND TI2.ItemID not in (
			Select ISNULL(UseCaseID,'') From XBOLTAPP.PIM_ELM_INST Where ElmItemID = #{elmItemID} AND ProcInstNo = #{procInstNo}
		)
		
		
			AND (TIFA.PlainText Like N'%'+#{searchValue}+'%'	 or TIA.PlainText Like N'%'+#{searchValue}+'%'	)
			
	 order by
		TI.ClassCode ASC, TIA.PlainText ASC

SELECT Row_Number()OVER(ORDER BY TI.ClassCode ASC, TOT.Name ,TIA.PlainText ASC ) as RNUM , TI.ItemID AS s_itemID, TI.ClassCode, ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , TIT.ItemTypeCode, TIF.ItemID, TIF.CategoryCode, ISNULL(TIS.SCOUNT, 0) AS SCOUNT , TIFA.PlainText as ParentName, TIA.PlainText as ItemName, TD.Name as ClassName, TTD.Name as TypeName, ISNULL(TT.Name, '') as TeamName, TOT.Name as OwnerTeamName , TM.Name , Convert(nvarchar(20),ISNULL(TCS.ValidFrom,TI.LastUpdated), 111) AS LastUpdated , TI.Version, TI.Identifier, TIFA2.PlainText as ProcessInfo , ISNULL(XBOLTADM.fn_GetMyAbsPathForList(TI.ItemID, #{languageID}), '') AS getPath , 0 AS CHK , TSD.Name AS StatusName , TI.Status AS Status , CXN.ItemID AS CXNItemID , CXN.ClassCode AS CXNClassCode , CXNCLS.Name AS CXNClassName , TI.OwnerTeamID , ( SELECT Count(*) FROM XBOLTADM.TB_ITEM WHERE ItemID in (Select Distinct ItemID From XBOLTADM.TB_ITEM WHERE ItemID in (Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1')
OR ItemID in (Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1')
) And ClassCode = TI.ClassCode ) AS ClassCNT FROM XBOLTADM.TB_ITEM TI Left outer join ( SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT FROM XBOLTADM.TB_ITEM WHERE Deleted != '1' GROUP BY FromItemID ) TIS on TIS.FromItemID = TI.ItemID Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID AND TIF.CategoryCode = 'ST1' Left Outer JOIN XBOLTADM.TB_ITEM_CLASS TIT ON TI.ClassCode = TIT.ItemClassCode Left Outer Join XBOLTADM.TB_ITEM_ATTR TIFA on TIF.FromItemID = TIFA.ItemID AND TIFA.AttrTypeCode = 'AT00001' AND TIFA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TTD on TI.ItemTypeCode = TTD.TypeCode AND TTD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIFA2 on TI.ItemID = TIFA2.ItemID AND TIFA2.AttrTypeCode = 'AT00003' AND TIFA2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM CXN ON (CXN.FromItemID = TI.ItemID OR CXN.ToItemID = TI.ItemID) And (CXN.FromItemID = #{s_itemID} OR CXN.ToItemID = #{s_itemID}) And CXN.Deleted != 1 And CXN.CategoryCode = 'CN' Left outer join XBOLTADM.TB_DICTIONARY CXNCLS on CXN.ClassCode = CXNCLS.TypeCode AND CXNCLS.LanguageID = #{languageID} Left outer join XBOLTADM.TB_CHANGE_SET TCS ON TCS.ChangeSetID = TI.CurChangeSet WHERE TI.ItemID in ( Select Distinct TI.ItemID From XBOLTADM.TB_ITEM TI WHERE TI.ItemID in ( Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1' )
OR TI.ItemID in ( Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'CN' AND Deleted != '1' )
)
AND TI.ClassCode = #{ClassCode}
AND TI.CompanyID = #{CompanyCode}
AND ItemTypeCode IN
${item}
AND TI.ClassCode IN
${item}
AND TI.CategoryCode != 'TOJ'
order by TI.ClassCode ASC, TOT.Name ASC, CXNClassCode, TI.Identifier ASC, TIA.PlainText ASC

 SELECT Distinct TI.ClassCode, TD.Name As ClassName
 FROM XBOLTADM.TB_ITEM TI
 Left outer join (
			SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT 
			FROM XBOLTADM.TB_ITEM 
			WHERE Deleted != '1'
			GROUP BY FromItemID 
			) TIS on TIS.FromItemID = TI.ItemID
Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
WHERE TI.ItemID in ( Select Distinct TI.ItemID From XBOLTADM.TB_ITEM TI WHERE 
					TI.ItemID in (
						Select FromItemID
						From XBOLTADM.TB_ITEM
						WHERE ToItemID =  #{s_itemID}
							AND CategoryCode = 'CN'
							AND Deleted != '1'
					)
					OR
					TI.ItemID in (
						Select ToItemID
						From XBOLTADM.TB_ITEM 
						WHERE FromItemID =  #{s_itemID}
							AND CategoryCode = 'CN'
							AND Deleted != '1'
					)
		)
		
		AND TI.ClassCode = #{ClassCode}
		
		
		AND TI.CompanyID = #{CompanyCode}
		
		
		AND TI.ItemTypeCode IN 
				
					${item}
				
		
		
		AND TI.ClassCode IN 
				
					${item}
				
		
		   AND TI.CategoryCode != 'TOJ' 	
	 order by
		TI.ClassCode ASC

SELECT Row_Number()OVER(ORDER BY TI.ClassCode ASC, TIA.PlainText ASC ) as RNUM , TI.ItemID AS s_itemID , TIA.PlainText as ItemName , TI.ClassCode , TD.Name AS ClassName , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg FROM XBOLTADM.TB_ITEM_OCC TIO Left Outer Join XBOLTADM.TB_ITEM TI on TIO.ObjectID = TI.ItemID Left Outer JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TIO.ObjectID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} WHERE TIO.ModelID = (
SELECT ModelID FROM XBOLTADM.TB_MODEL WHERE ItemID = #{s_itemID}
#{s_itemID}
) ORDER BY TI.ClassCode ASC, TIA.PlainText ASC

SELECT DISTINCT TI.ClassCode, TD.Name as ClassName FROM XBOLTADM.TB_ITEM TI Left outer join ( SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT FROM XBOLTADM.TB_ITEM WHERE Deleted != '1' GROUP BY FromItemID ) TIS on TIS.FromItemID = TI.ItemID Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
WHERE TI.ItemID in ( Select Distinct TI.ItemID From XBOLTADM.TB_ITEM TI WHERE TI.ItemID in ( Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID}
)
OR TI.ItemID in ( Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} )
) order by TI.ClassCode ASC

SELECT DISTINCT TI.CompanyID, ISNULL(TT.Name, '') as TeamName FROM XBOLTADM.TB_ITEM TI Left outer join ( SELECT FromItemID, ISNULL(COUNT(DISTINCT ToItemID), 0) AS SCOUNT FROM XBOLTADM.TB_ITEM WHERE Deleted != '1' GROUP BY FromItemID ) TIS on TIS.FromItemID = TI.ItemID Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID}
WHERE TI.ItemID in ( Select Distinct TI.ItemID From XBOLTADM.TB_ITEM TI WHERE TI.ItemID in ( Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID}
)
OR TI.ItemID in ( Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} ) ) order by TI.CompanyID ASC

SELECT TI.ItemID, TIFA.PlainText AS FatherName, TIA.PlainText as ItemName, TD.Name as ClassName, ISNULL(TT.Name, '') as TeamName
	, TOT.Name as OwnerTeamName	, TI.Identifier, TSD.Name AS StatusName
FROM
		XBOLTADM.TB_ITEM TI
		Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID AND TIF.CategoryCode = 'ST1'
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIFA on TIF.FromItemID = TIFA.ItemID AND TIFA.AttrTypeCode = 'AT00001' AND TIFA.LanguageID = #{languageID} 
		Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
		Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS'
		Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID  = #{languageID} 
		Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID  = #{languageID}
		Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID
		Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID  = #{languageID}
		Left outer join XBOLTADM.TB_ITEM_ATTR TIAF on TI.ItemID = TIAF.ItemID AND TIAF.AttrTypeCode = 'AT00001' AND TIAF.LanguageID  = #{languageID}

		
		TI.ClassCode = #{ClassCode}
		
		
		AND TI.ItemTypeCode = #{ItemTypeCode}
		

AND TI.ItemID NOT IN (
	SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE ItemID in ( 
		SELECT FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID}
	
		)
			OR
			TI.ItemID in (
				Select ToItemID
				From XBOLTADM.TB_ITEM 
				WHERE FromItemID =  #{s_itemID}
			
			)
			
	 )
	
		
			AND TIA.PlainText like N'%'+#{searchValue}+'%'
		
		
			AND TI.Identifier like N'%'+#{searchValue}+'%'
		
		
			AND TIAF.PlainText like N'%'+#{searchValue}+'%'
		
	
	
		AND TIF.FromItemID = #{parentCode}
	
	
		AND TT.TeamID = #{newCompanyCode}
	

	order by
		TI.ClassCode ASC, TIFA.PlainText ASC, TIA.PlainText ASC

SELECT Row_Number()OVER(ORDER BY XBOLTADM.fn_GetMyAbsPathForList(TI.ItemID, #{languageID}) ASC, TIA.PlainText ASC ) as RNUM , 0 AS CHK , TI.ItemID , XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID, #{languageID} ) AS FatherName , TIA.PlainText as ItemName , TD.Name as ClassName , ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , TI.Identifier , TSD.Name AS StatusName , TI.AuthorID FROM XBOLTADM.TB_ITEM TI Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID AND TIF.CategoryCode = 'ST1' Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
TI.ClassCode = #{ClassCode}
AND TI.ItemTypeCode = #{ItemTypeCode}
AND TI.ItemID NOT IN ( Select FromItemID From XBOLTADM.TB_ITEM WHERE ToItemID = #{s_itemID} OR TI.ItemID in ( Select ToItemID From XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID}
) )
AND TIA.PlainText like N'%'+#{searchValue}+'%'
AND TI.Identifier like N'%'+#{searchValue}+'%'
AND TIAF.PlainText like N'%'+#{searchValue}+'%'
AND TT.TeamID = #{newCompanyCode}
order by FatherName ASC, TIA.PlainText ASC

SELECT TI.ItemID, TIFA.PlainText AS FatherName, TIA.PlainText as ItemName, TD.Name as ClassName, ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , TI.Identifier FROM XBOLTADM.TB_ITEM TI Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID Left Outer Join XBOLTADM.TB_ITEM_ATTR TIFA on TIF.FromItemID = TIFA.ItemID AND TIFA.AttrTypeCode = 'AT00001' Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001'
TI.ClassCode = #{ClassCode}
AND TI.CompanyID = #{newCompanyCode}
order by TI.ClassCode ASC, TIFA.PlainText ASC, TIA.PlainText ASC

SELECT TI.ItemID, TIFA.PlainText AS FatherName, TIA.PlainText as ItemName, TD.Name as ClassName, ISNULL(TT.Name, '') as TeamName
	, TOT.Name as OwnerTeamName	, TI.Identifier
FROM
		XBOLTADM.TB_ITEM TI
		Left Outer Join XBOLTADM.TB_ITEM TIF on TI.ItemID = TIF.ToItemID AND TIF.CategoryCode 'ST1'
