SELECT Row_Number()OVER(ORDER BY ISNULL(A.RelID, '') ASC) as RNUM, * FROM( SELECT DISTINCT
T3.ItemID As CnItemID
T1.ItemID As CnItemID
, T2.ItemID As RelItemID , ISNULL(T2.Identifier, '') As RelID , ISNULL(T3.Identifier, '') As PrcID , T4.PlainText As RelName , T5.PlainText As PrcName , ISNULL(XBOLTADM.fn_GetMyAbsPathForList(T1.FromItemID, #{languageID}), '') AS RelPath , ISNULL(XBOLTADM.fn_GetMyAbsPathForList(T1.ToItemID, #{languageID}), '') AS PrcPath
, T3.ItemID As PrcItemID
, T1.ToItemID As PrcItemID
, T1.ItemTypeCode , T1.ClassCode , (SELECT Icon FROM XBOLTADM.TB_ITEM_TYPE WHERE ItemTypeCode = T2.ItemTypeCode) As FromItemIcon , (SELECT Icon FROM XBOLTADM.TB_ITEM_TYPE WHERE ItemTypeCode = T3.ItemTypeCode) As ToItemIcon , T2.AuthorID As RelAuthorID , T2.LockOwner As RelLockOwner , T3.AuthorID As PrcAuthorID , T3.LockOwner As PrcLockOwner , T2.Identifier As RelIdentifier , T3.Identifier As PrcIdentifier , T2.Blocked As RelBlocked , T3.Blocked As PrcBlocked , T2.Status As RelStatus , T3.Status As PrcStatus FROM XBOLTADM.TB_ITEM T1 Left Outer Join XBOLTADM.TB_ITEM T2 on T1.FromItemID = T2.ItemID
Left Outer Join XBOLTADM.TB_ITEM CNX on T1.ToItemID = CNX.ToItemID AND CNX.CategoryCode = 'ST1' Left Outer Join XBOLTADM.TB_ITEM T3 on T3.ItemID = CNX.FromItemID
Left Outer Join XBOLTADM.TB_ITEM T3 on T1.ToItemID = T3.ItemID
Left Outer Join XBOLTADM.TB_ITEM_ATTR T4 on T1.FromItemID = T4.ItemID AND T4.AttrTypeCode = 'AT00001' AND T4.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_ITEM_ATTR T5 on T3.ItemID = T5.ItemID AND T5.AttrTypeCode = 'AT00001' AND T5.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_ITEM_ATTR T5 on T1.ToItemID = T5.ItemID AND T5.AttrTypeCode = 'AT00001' AND T5.LanguageID = #{languageID}
WHERE T1.ItemTypeCode = #{varFilter} AND T1.Deleted != 1
AND T1.FromItemID = #{s_itemID} AND T1.ToItemID = #{s_itemID}
)A Order By RelID , PrcID

