SELECT TI.ItemID AS ItemID , TI.Classcode As ClassCode , TI.ItemTypeCode As ItemTypeCode , TI.Identifier AS Identifier , TI.LastUpdated , TIA.PlainText AS ItemName , TI.SortNum , TIA1.PlainText AS PlainText1 , TIA2.PlainText AS PlainText2 , TIA3.PlainText AS PlainText3 , TIA4.PlainText AS PlainText4 , TAT1.DataType AS DataType1 , TAT2.DataType AS DataType2 , TAT3.DataType AS DataType3 , TAT4.DataType AS DataType4 , TIA1.LovCode As LovCode1 , TIA2.LovCode As LovCode2 , TIA3.LovCode As LovCode3 , TIA4.LovCode As LovCode4 , TAT1.AttrTypeCode AS AttrTypeCode1 , TAT2.AttrTypeCode AS AttrTypeCode2 , TAT3.AttrTypeCode AS AttrTypeCode3 , TAT4.AttrTypeCode AS AttrTypeCode4 , TAT1.SubAttrTypeCode AS SubAttrTypeCode1 , TAT2.SubAttrTypeCode AS SubAttrTypeCode2 , TAT3.SubAttrTypeCode AS SubAttrTypeCode3 , TAT4.SubAttrTypeCode AS SubAttrTypeCode4 FROM XBOLTADM.TB_ITEM TI Left outer join XBOLTADM.TB_ITEM TITO ON TITO.ToITemID = TI.ItemID And TITO.CategoryCode = 'ST1' And TITO.Deleted != 1 Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left outer Join XBOLTADM.TB_ITEM_CLASS TIC ON TIC.ItemClassCode = TI.ClassCode
Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT1 ON TAT1.AttrTypeCode = #{attrTypeCode_1} Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT2 ON TAT2.AttrTypeCode = #{attrTypeCode_2} Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT3 ON TAT3.AttrTypeCode = #{attrTypeCode_3} Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT4 ON TAT4.AttrTypeCode = #{attrTypeCode_4}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA1 ON TIA1.AttrTypeCode = TAT1.AttrTypeCode AND TIA1.LanguageID = #{languageID} AND TIA1.ItemID = TI.ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 ON TIA2.AttrTypeCode = TAT2.AttrTypeCode AND TIA2.LanguageID = #{languageID} AND TIA2.ItemID = TI.ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA3 ON TIA3.AttrTypeCode = TAT3.AttrTypeCode AND TIA3.LanguageID = #{languageID} AND TIA3.ItemID = TI.ItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA4 ON TIA4.AttrTypeCode = TAT4.AttrTypeCode AND TIA4.LanguageID = #{languageID} AND TIA4.ItemID = TI.ItemID WHERE TI.Deleted != 1 AND TI.ItemID IN (SELECT ToItemID FROM XBOLTADM.TB_ITEM WHERE FromItemID = #{s_itemID} AND CategoryCode = 'ST1') Order by TI.Identifier, TI.ClassCode, TIA.PlainText ASC

 		Select CheckOutOption
 		  From XBOLTADM.TB_ITEM_CLASS 
	 	Where ItemClassCode = #{ItemClassCode}

With ItemTypeTable ( ItemTypeCode, CxnType, CxnTypecode) AS ( Select FromItemTypeCode AS ItemTypeCode, 'To' As CxnType, ItemTypeCode AS CxnTypecode From XBOLTADM.TB_ITEM_TYPE Where ToItemTypeCode = #{itemTypeCode} AND category = 'CN'
Union All
Select ToItemTypeCode AS ItemTypeCode, 'From' As CxnType, ItemTypeCode AS CxnTypecode From XBOLTADM.TB_ITEM_TYPE Where FromItemTypeCode = #{itemTypeCode} AND category = 'CN' ) Select CxnType, CxnTypeCode From ItemTypeTable Where ItemTypeCode = #{cxnTypeCode}

Select REPLACE(CONVERT(VARCHAR, CAST(Count(*) AS MONEY),1),'.00','') AS ItemCnt from XBOLTADM.TB_ITEM TI LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS ON TCLS.ItemClassCode = TI.ClassCode Where AuthorID = #{actorID} AND CategoryCode = 'OJ' AND Deleted != 1
AND Status = #{status}
AND Status in (${MultiStatus})
AND Status != #{notStatus}
AND TCLS.ChangeMgt = '1'
AND TCLS.ChangeMgt = '0'

